import { readFile, writeFile, mkdir, readdir, stat } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import { getFormicDir, getSkillsDir, getBundledSkillsPath } from '../utils/paths.js';

/**
 * Get the path to the workspace skills directory (.claude/skills/)
 */
export function getWorkspaceSkillsPath(): string {
  return getSkillsDir();
}

/**
 * Get the legacy skills path (.formic/skills/)
 */
export function getLegacySkillsPath(): string {
  return path.join(getFormicDir(), 'skills');
}

/**
 * Check if skills have already been copied to the workspace
 * Checks both new (.claude/skills/) and legacy (.formic/skills/) locations
 */
export function skillsExistInWorkspace(): boolean {
  const newPath = getWorkspaceSkillsPath();
  const legacyPath = getLegacySkillsPath();
  return existsSync(newPath) || existsSync(legacyPath);
}

/**
 * Recursively copy a directory
 */
async function copyDirectory(src: string, dest: string): Promise<void> {
  // Create destination directory if it doesn't exist
  if (!existsSync(dest)) {
    await mkdir(dest, { recursive: true });
  }

  const entries = await readdir(src, { withFileTypes: true });

  for (const entry of entries) {
    const srcPath = path.join(src, entry.name);
    const destPath = path.join(dest, entry.name);

    if (entry.isDirectory()) {
      await copyDirectory(srcPath, destPath);
    } else {
      const content = await readFile(srcPath, 'utf-8');
      await writeFile(destPath, content, 'utf-8');
    }
  }
}

/**
 * Copy bundled skills to the workspace .claude/skills/ directory
 * Only copies if skills don't already exist in the workspace (checks both new and legacy locations)
 */
export async function copySkillsToWorkspace(): Promise<{ copied: boolean; skills: string[] }> {
  // Skip if skills already exist in either location
  if (skillsExistInWorkspace()) {
    console.log('[Skills] Skills already exist in workspace, skipping copy');
    return { copied: false, skills: [] };
  }

  const bundledSkillsPath = getBundledSkillsPath();
  const workspaceSkillsPath = getWorkspaceSkillsPath(); // Points to .claude/skills/

  // Check if bundled skills exist
  if (!existsSync(bundledSkillsPath)) {
    console.warn('[Skills] Bundled skills directory not found at:', bundledSkillsPath);
    return { copied: false, skills: [] };
  }

  try {
    // Ensure .claude directory exists
    const claudeDir = path.dirname(workspaceSkillsPath);
    if (!existsSync(claudeDir)) {
      await mkdir(claudeDir, { recursive: true });
    }

    // Copy the entire skills directory to .claude/skills/
    await copyDirectory(bundledSkillsPath, workspaceSkillsPath);

    // Get list of copied skills
    const skillDirs = await readdir(workspaceSkillsPath);
    const skills = skillDirs.filter(async (dir) => {
      const skillPath = path.join(workspaceSkillsPath, dir);
      const stats = await stat(skillPath);
      return stats.isDirectory();
    });

    console.log('[Skills] Copied skills to workspace .claude/skills/:', skills);
    return { copied: true, skills };
  } catch (error) {
    console.error('[Skills] Error copying skills to workspace:', error);
    return { copied: false, skills: [] };
  }
}

/**
 * Get the path to a specific skill in the workspace
 * Checks new location (.claude/skills/) first, then falls back to legacy (.formic/skills/)
 */
export function getSkillPath(skillName: string): string {
  const newPath = path.join(getWorkspaceSkillsPath(), skillName, 'SKILL.md');
  const legacyPath = path.join(getLegacySkillsPath(), skillName, 'SKILL.md');

  // Prefer new location, fall back to legacy
  if (existsSync(newPath)) {
    return newPath;
  }
  if (existsSync(legacyPath)) {
    return legacyPath;
  }

  // Default to new location for new files
  return newPath;
}

/**
 * Check if a specific skill exists in the workspace (either location)
 */
export function skillExists(skillName: string): boolean {
  const newPath = path.join(getWorkspaceSkillsPath(), skillName, 'SKILL.md');
  const legacyPath = path.join(getLegacySkillsPath(), skillName, 'SKILL.md');
  return existsSync(newPath) || existsSync(legacyPath);
}

/**
 * Get the content of a skill file
 */
export async function getSkillContent(skillName: string): Promise<string | null> {
  const skillPath = getSkillPath(skillName);

  if (!existsSync(skillPath)) {
    return null;
  }

  return await readFile(skillPath, 'utf-8');
}

import { readFile, writeFile } from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import type { SubtasksFile, Subtask, SubtaskStatus, Task, TaskStatus, WorkflowStep } from '../../types/index.js';
import { getWorkspacePath } from '../utils/paths.js';

const SUBTASKS_FILENAME = 'subtasks.json';

/**
 * Get the path to the subtasks.json file for a task
 */
export function getSubtasksPath(docsPath: string): string {
  return path.join(getWorkspacePath(), docsPath, SUBTASKS_FILENAME);
}

/**
 * Check if subtasks.json exists for a task
 */
export function subtasksExist(docsPath: string): boolean {
  return existsSync(getSubtasksPath(docsPath));
}

/**
 * Load and parse subtasks.json for a task
 * Returns null if file doesn't exist or is invalid
 */
export async function loadSubtasks(docsPath: string): Promise<SubtasksFile | null> {
  const subtasksPath = getSubtasksPath(docsPath);
  console.log(`[Subtasks] Loading subtasks from: ${subtasksPath}`);

  if (!existsSync(subtasksPath)) {
    console.log(`[Subtasks] File does not exist: ${subtasksPath}`);
    return null;
  }

  try {
    const content = await readFile(subtasksPath, 'utf-8');
    const data = JSON.parse(content) as SubtasksFile;

    // Basic validation
    if (!data.version || !data.subtasks || !Array.isArray(data.subtasks)) {
      console.warn('[Subtasks] Invalid subtasks.json structure');
      return null;
    }

    // Normalize invalid status values to prevent infinite execution loops
    const VALID_STATUSES: Set<string> = new Set(['pending', 'in_progress', 'completed', 'skipped']);
    const SYNONYM_MAP: Record<string, SubtaskStatus> = {
      'done': 'completed',
      'complete': 'completed',
      'finished': 'completed',
      'skip': 'skipped',
    };

    for (const subtask of data.subtasks) {
      if (!VALID_STATUSES.has(subtask.status)) {
        const normalized = SYNONYM_MAP[subtask.status] ?? 'pending';
        console.warn(`[Subtasks] Normalizing invalid status "${subtask.status}" → "${normalized}" for subtask ${subtask.id}`);
        subtask.status = normalized;
      }
    }

    console.warn(`[Subtasks] Loaded ${data.subtasks.length} subtasks`);
    return data;
  } catch (error) {
    console.error('[Subtasks] Failed to load subtasks.json:', error);
    return null;
  }
}

/**
 * Save subtasks.json for a task
 */
export async function saveSubtasks(docsPath: string, subtasks: SubtasksFile): Promise<boolean> {
  const subtasksPath = getSubtasksPath(docsPath);

  try {
    // Update the updatedAt timestamp
    subtasks.updatedAt = new Date().toISOString();

    await writeFile(subtasksPath, JSON.stringify(subtasks, null, 2), 'utf-8');
    return true;
  } catch (error) {
    console.error('[Subtasks] Failed to save subtasks.json:', error);
    return false;
  }
}

/**
 * Update the status of a single subtask
 */
export async function updateSubtaskStatus(
  docsPath: string,
  subtaskId: string,
  status: SubtaskStatus
): Promise<{ success: boolean; subtask?: Subtask }> {
  const subtasks = await loadSubtasks(docsPath);

  if (!subtasks) {
    return { success: false };
  }

  const subtask = subtasks.subtasks.find(s => s.id === subtaskId);
  if (!subtask) {
    return { success: false };
  }

  subtask.status = status;

  // Set completedAt timestamp when marking as completed
  if (status === 'completed') {
    subtask.completedAt = new Date().toISOString();
  } else {
    delete subtask.completedAt;
  }

  const saved = await saveSubtasks(docsPath, subtasks);
  return { success: saved, subtask };
}

/**
 * Get completion statistics for subtasks
 */
export function getCompletionStats(subtasks: SubtasksFile): {
  total: number;
  completed: number;
  skipped: number;
  inProgress: number;
  pending: number;
  percentage: number;
} {
  const total = subtasks.subtasks.length;
  const completed = subtasks.subtasks.filter(s => s.status === 'completed').length;
  const skipped = subtasks.subtasks.filter(s => s.status === 'skipped').length;
  const inProgress = subtasks.subtasks.filter(s => s.status === 'in_progress').length;
  const pending = subtasks.subtasks.filter(s => s.status === 'pending').length;
  // Both completed and skipped count toward progress
  const doneCount = completed + skipped;
  const percentage = total > 0 ? Math.round((doneCount / total) * 100) : 0;

  return { total, completed, skipped, inProgress, pending, percentage };
}

/**
 * Check if all subtasks are completed or skipped
 * Skipped subtasks are those that require manual verification and cannot be automated
 */
export function isAllComplete(subtasks: SubtasksFile): boolean {
  if (subtasks.subtasks.length === 0) {
    return true; // No subtasks means complete
  }
  // Both 'completed' and 'skipped' count as done for workflow purposes
  return subtasks.subtasks.every(s => s.status === 'completed' || s.status === 'skipped');
}

/**
 * Get all incomplete subtasks (pending or in_progress, not skipped)
 */
export function getIncompleteSubtasks(subtasks: SubtasksFile): Subtask[] {
  return subtasks.subtasks.filter(s => s.status !== 'completed' && s.status !== 'skipped');
}

/**
 * Format incomplete subtasks as a string for agent feedback
 */
export function formatIncompleteSubtasksForPrompt(subtasks: SubtasksFile): string {
  const incomplete = getIncompleteSubtasks(subtasks);

  if (incomplete.length === 0) {
    return 'All subtasks are complete.';
  }

  const lines = incomplete.map(s => {
    const statusLabel = s.status === 'in_progress' ? '[IN PROGRESS]' : '[PENDING]';
    return `- ${statusLabel} ${s.id}: ${s.content}`;
  });

  return `The following subtasks are NOT yet complete:\n${lines.join('\n')}`;
}

/**
 * Calculate task progress percentage (0-100) based on workflow stage and subtask completion.
 *
 * Progress model:
 * - Stage progress (0-25%): pending/todo=0%, briefing=5%, planning=18%, running=25%, review/done=100%
 * - Subtask progress (25-100%): During 'execute' stage, remaining 75% divided among subtasks
 *
 * @param task - The task to calculate progress for
 * @returns Progress percentage (0-100)
 */
export async function calculateTaskProgress(task: Task): Promise<number> {
  const { status, workflowStep, docsPath, id } = task;

  // Bootstrap task: 0% when pending/todo, 100% when done
  if (id === 't-bootstrap') {
    if (status === 'done' || status === 'review') {
      return 100;
    }
    if (status === 'todo') {
      return 0;
    }
    // If running, estimate based on status
    if (status === 'briefing') return 10;
    if (status === 'planning') return 30;
    if (status === 'running') return 60;
    return 0;
  }

  // Completed tasks
  if (status === 'done') {
    return 100;
  }

  // Review tasks (workflow complete, awaiting human review)
  if (status === 'review') {
    return 100;
  }

  // Todo tasks (not started)
  if (status === 'todo') {
    return 0;
  }

  // Stage-based progress for active workflow
  // briefing = 5%, planning = 18%, running = 25% (base for execute)
  const stageProgress: Record<TaskStatus, number> = {
    'todo': 0,
    'queued': 0,
    'briefing': 5,
    'planning': 18,
    'declaring': 20,
    'running': 25,
    'architecting': 50,
    'verifying': 80,
    'review': 100,
    'done': 100,
    'blocked': 0,
  };

  let progress = stageProgress[status] ?? 0;

  // Add subtask progress during execution phase
  if (status === 'running' && (workflowStep === 'execute' || workflowStep === 'complete')) {
    const subtasks = await loadSubtasks(docsPath);

    if (subtasks && subtasks.subtasks.length > 0) {
      const stats = getCompletionStats(subtasks);
      // Subtasks contribute 75% of total progress (25% to 100%)
      // Both completed and skipped count toward progress
      const doneCount = stats.completed + stats.skipped;
      const subtaskProgress = (doneCount / stats.total) * 75;
      progress = 25 + subtaskProgress;
    }
    // If no subtasks.json yet during execute, stay at 25%
  }

  return Math.min(100, Math.round(progress));
}

// lease-test: verified
/**
 * Lease Manager Service
 * Provides atomic all-or-nothing file lease acquisition, renewal, and release
 * for lease-based concurrency control of parallel task execution.
 * Includes priority preemption, deadlock detection, and disk persistence.
 */

import { exec } from 'node:child_process';
import { promisify } from 'node:util';
import { writeFile, readFile } from 'node:fs/promises';
import path from 'node:path';
import type { FileLease, LeaseRequest, LeaseResult, FileConflict, LeaseStoreSnapshot } from '../../types/index.js';
import { getFormicDir, getWorkspacePath } from '../utils/paths.js';
import { getTask, updateTaskStatus } from './store.js';
import { broadcastLeaseReleased } from './boardNotifier.js';
import { internalEvents, LEASE_RELEASED, LEASE_ACQUIRED, requestTaskStop } from './internalEvents.js';

const execAsync = promisify(exec);

import { engineConfig } from './engineConfig.js';

/** Active-task predicate: returns true when a task has a live workflow process. */
let isTaskActive: ((taskId: string) => boolean) | null = null;

/**
 * Register the active-task predicate callback. Used by workflow.ts to expose
 * its activeWorkflows knowledge to leaseManager so expiry checks can protect
 * leases held by tasks with live child processes.
 */
export function registerActiveTaskPredicate(fn: (taskId: string) => boolean): void {
  isTaskActive = fn;
}

/** In-memory lease store: filePath → FileLease */
const leaseStore = new Map<string, FileLease>();

/** Recorded file hashes for collision detection: taskId → Map<filePath, hash> */
const fileHashStore = new Map<string, Map<string, string>>();

/** Wait-for map: taskId → filePath the task is waiting to acquire */
const waitForMap = new Map<string, string>();

/** Priority rank for comparison: higher number = higher priority */
const PRIORITY_RANK: Record<string, number> = { low: 0, medium: 1, high: 2 };

/**
 * Acquire file leases atomically (all-or-nothing).
 * If any exclusive file is already leased by another task, the entire request is denied.
 * Shared files are not exclusively locked.
 */
export function acquireLeases(request: LeaseRequest): LeaseResult {
  const { taskId, exclusiveFiles, sharedFiles } = request;
  const durationMs = request.leaseDurationMs ?? engineConfig.leaseDurationMs;
  const now = new Date();
  const expiresAt = new Date(now.getTime() + durationMs);

  // Clean expired leases before checking
  cleanExpiredLeases();

  // Check for conflicts on exclusive files
  const conflictingFiles: string[] = [];
  for (const filePath of exclusiveFiles) {
    const existing = leaseStore.get(filePath);
    if (existing && existing.taskId !== taskId) {
      conflictingFiles.push(filePath);
      continue;
    }
    // Also check for shared leases on this file held by other tasks
    for (const [key, lease] of leaseStore.entries()) {
      if (key.startsWith(`${filePath}::`) && lease.taskId !== taskId) {
        conflictingFiles.push(filePath);
        break;
      }
    }
  }

  // Check for conflicts on shared files against exclusive leases
  for (const filePath of sharedFiles) {
    const existing = leaseStore.get(filePath);
    if (existing && existing.taskId !== taskId && existing.leaseType === 'exclusive') {
      conflictingFiles.push(filePath);
    }
  }

  if (conflictingFiles.length > 0) {
    console.warn(`[LeaseManager] Lease denied for task ${taskId}: conflicts on ${conflictingFiles.join(', ')}`);
    return { granted: false, leases: [], conflictingFiles };
  }

  // Grant all leases atomically — all conflict checks passed
  const grantedLeases: FileLease[] = [];

  for (const filePath of exclusiveFiles) {
    const lease: FileLease = {
      filePath,
      taskId,
      acquiredAt: now.toISOString(),
      expiresAt: expiresAt.toISOString(),
      leaseType: 'exclusive',
    };
    leaseStore.set(filePath, lease);
    grantedLeases.push(lease);
  }

  for (const filePath of sharedFiles) {
    const lease: FileLease = {
      filePath,
      taskId,
      acquiredAt: now.toISOString(),
      expiresAt: expiresAt.toISOString(),
      leaseType: 'shared',
    };
    // Shared files don't block others - store with task-scoped key
    leaseStore.set(`${filePath}::${taskId}`, lease);
    grantedLeases.push(lease);
  }

  console.warn(`[LeaseManager] Leases granted for task ${taskId}: ${exclusiveFiles.length} exclusive, ${sharedFiles.length} shared`);
  internalEvents.emit(LEASE_ACQUIRED, { taskId, leases: grantedLeases });
  persistLeases().catch(e => console.warn('[LeaseManager] persist error:', e));
  return { granted: true, leases: grantedLeases, conflictingFiles: [] };
}

/**
 * Release all leases held by a task
 */
export function releaseLeases(taskId: string): void {
  let released = 0;
  const releasedFiles: string[] = [];
  for (const [key, lease] of leaseStore.entries()) {
    if (lease.taskId === taskId) {
      if (lease.leaseType === 'exclusive') {
        releasedFiles.push(lease.filePath);
      }
      leaseStore.delete(key);
      released++;
    }
  }
  if (released > 0) {
    console.warn(`[LeaseManager] Released ${released} lease(s) for task ${taskId}`);
    broadcastLeaseReleased(taskId, releasedFiles);
    internalEvents.emit(LEASE_RELEASED, taskId, releasedFiles);
  }

  // Clean up file hash records
  fileHashStore.delete(taskId);
  persistLeases().catch(e => console.warn('[LeaseManager] persist error:', e));
}

/**
 * Renew all leases for a task by extending their expiration.
 * No longer calls cleanExpiredLeases — expiry-driven cleanup is exclusively
 * handled by acquireLeases (the mutation entry point) and the watchdog.
 */
export function renewLeases(taskId: string, durationMs?: number): boolean {
  const extension = durationMs ?? engineConfig.leaseDurationMs;
  const newExpiresAt = new Date(Date.now() + extension).toISOString();
  let renewed = 0;

  for (const lease of leaseStore.values()) {
    if (lease.taskId === taskId) {
      lease.expiresAt = newExpiresAt;
      renewed++;
    }
  }

  if (renewed > 0) {
    console.warn(`[LeaseManager] Renewed ${renewed} lease(s) for task ${taskId}`);
    return true;
  }
  return false;
}

/**
 * Get all leases held by a specific task
 */
export function getLeasesByTask(taskId: string): FileLease[] {
  const leases: FileLease[] = [];
  for (const lease of leaseStore.values()) {
    if (lease.taskId === taskId) {
      leases.push(lease);
    }
  }
  return leases;
}

/**
 * Get all active leases, filtering out expired leases whose holder is not active.
 * This is a read-only operation — no mutation, no events, no persistence.
 */
export function getAllLeases(): FileLease[] {
  const now = Date.now();
  return Array.from(leaseStore.values()).filter(lease => {
    if (new Date(lease.expiresAt).getTime() > now) return true;
    // Expired but holder is active — still considered leased
    return isTaskActive ? isTaskActive(lease.taskId) : false;
  });
}

/**
 * Check if a file is currently leased (optionally excluding a specific task).
 * Expired leases whose holder is not active are treated as not leased.
 * This is a read-only operation — no mutation, no events, no persistence.
 */
export function isFileLeased(filePath: string, excludeTaskId?: string): boolean {
  const now = Date.now();
  const lease = leaseStore.get(filePath);
  if (!lease) return false;
  if (excludeTaskId && lease.taskId === excludeTaskId) return false;
  // Expired and holder not active — treat as free
  if (new Date(lease.expiresAt).getTime() <= now && !(isTaskActive && isTaskActive(lease.taskId))) {
    return false;
  }
  return true;
}

/**
 * Check whether a file would conflict if the given taskId intended to acquire it
 * exclusively. Mirrors the conflict logic in acquireLeases() so pre-dispatch
 * checks and actual lease grants are consistent.
 *
 * A conflict exists when:
 * 1. The file has an exclusive lease held by a different task, OR
 * 2. The file has one or more shared leases held by different tasks
 *
 * Expired leases are cleaned before checking, matching acquireLeases behaviour.
 * Returns true if there IS a conflict (i.e., the task would be denied).
 */
export function wouldConflict(filePath: string, taskId: string): boolean {
  // Clean expired leases before checking (consistent with acquireLeases)
  cleanExpiredLeases();

  // Check exclusive holder
  const exclusive = leaseStore.get(filePath);
  if (exclusive && exclusive.taskId !== taskId) {
    return true;
  }

  // Check shared holders — stored under filePath::taskId keys
  for (const [key, lease] of leaseStore.entries()) {
    if (key.startsWith(`${filePath}::`) && lease.taskId !== taskId) {
      return true;
    }
  }

  return false;
}

/**
 * Get the task ID that holds an exclusive lease on a file, or null if none.
 * Expired leases whose holder is not active are treated as not held.
 * Used to identify zombie lease holders.
 * This is a read-only operation — no mutation, no events, no persistence.
 */
export function getExclusiveLeaseHolder(filePath: string): string | null {
  const now = Date.now();
  const lease = leaseStore.get(filePath);
  if (!lease || lease.leaseType !== 'exclusive') return null;
  // Expired and holder not active — treat as not held
  if (new Date(lease.expiresAt).getTime() <= now && !(isTaskActive && isTaskActive(lease.taskId))) {
    return null;
  }
  return lease.taskId;
}

/**
 * Clean up expired leases from the store.
 *
 * Expired leases whose holder has a live workflow process are renewed in-place
 * (mirrors the watchdog's active-task guard). Leases whose holder is NOT active
 * are genuinely freed: deleted from the store, broadcast via boardNotifier,
 * emitted via internalEvents (LEASE_RELEASED), and persisted to leases.json.
 */
function cleanExpiredLeases(): void {
  const now = Date.now();
  const releasedExclusiveByTask = new Map<string, string[]>();

  for (const [key, lease] of leaseStore.entries()) {
    if (new Date(lease.expiresAt).getTime() <= now) {
      if (isTaskActive && isTaskActive(lease.taskId)) {
        // Active task: renew in-place instead of deleting
        const newExpiresAt = new Date(now + engineConfig.leaseDurationMs).toISOString();
        lease.expiresAt = newExpiresAt;
        console.warn(`[LeaseManager] Renewed expired lease for active task ${lease.taskId} on ${lease.filePath}`);
      } else {
        // Not active: genuinely free the lease
        if (lease.leaseType === 'exclusive') {
          const files = releasedExclusiveByTask.get(lease.taskId) || [];
          files.push(lease.filePath);
          releasedExclusiveByTask.set(lease.taskId, files);
        }
        leaseStore.delete(key);
      }
    }
  }

  // Emit LEASE_RELEASED and broadcast for genuinely freed leases
  for (const [taskId, files] of releasedExclusiveByTask) {
    console.warn(`[LeaseManager] Expired leases freed for inactive task ${taskId}: ${files.join(', ')}`);
    broadcastLeaseReleased(taskId, files);
    internalEvents.emit(LEASE_RELEASED, taskId, files);
  }

  if (releasedExclusiveByTask.size > 0) {
    persistLeases().catch(e => console.warn('[LeaseManager] persist error:', e));
  }
}

/**
 * Get all expired leases (used by watchdog)
 */
export function getExpiredLeases(): FileLease[] {
  const now = Date.now();
  const expired: FileLease[] = [];
  for (const lease of leaseStore.values()) {
    if (new Date(lease.expiresAt).getTime() <= now) {
      expired.push(lease);
    }
  }
  return expired;
}

/**
 * Record git hash-object hashes for shared files at task start
 * Used for optimistic concurrency collision detection
 */
export async function recordFileHashes(taskId: string, filePaths: string[], cwd: string): Promise<Map<string, string>> {
  const hashes = new Map<string, string>();

  for (const filePath of filePaths) {
    try {
      const { stdout } = await execAsync(`git hash-object "${filePath}"`, { cwd });
      const hash = stdout.trim();
      if (hash) {
        hashes.set(filePath, hash);
      }
    } catch {
      // File may not exist yet, skip it
      console.warn(`[LeaseManager] Could not hash file: ${filePath}`);
    }
  }

  fileHashStore.set(taskId, hashes);
  console.warn(`[LeaseManager] Recorded ${hashes.size} file hash(es) for task ${taskId}`);
  return hashes;
}

/**
 * Detect collisions on shared files by comparing current hashes to recorded ones
 */
export async function detectCollisions(taskId: string, cwd: string): Promise<FileConflict[]> {
  const baseHashes = fileHashStore.get(taskId);
  if (!baseHashes || baseHashes.size === 0) {
    return [];
  }

  const conflicts: FileConflict[] = [];

  for (const [filePath, expectedHash] of baseHashes.entries()) {
    try {
      const { stdout } = await execAsync(`git hash-object "${filePath}"`, { cwd });
      const actualHash = stdout.trim();
      if (actualHash && actualHash !== expectedHash) {
        conflicts.push({
          filePath,
          expectedHash,
          actualHash,
        });
      }
    } catch {
      // File may have been deleted, treat as conflict
      conflicts.push({
        filePath,
        expectedHash,
        actualHash: '<deleted>',
      });
    }
  }

  if (conflicts.length > 0) {
    console.warn(`[LeaseManager] Detected ${conflicts.length} collision(s) for task ${taskId}`);
  }

  return conflicts;
}

/**
 * Register that a task is waiting to acquire a lease on a file.
 * Used to build the wait-for graph for deadlock detection.
 */
export function recordWait(taskId: string, filePath: string): void {
  waitForMap.set(taskId, filePath);
}

/**
 * Unregister a task's wait record once it acquires or abandons the lease.
 */
export function clearWait(taskId: string): void {
  waitForMap.delete(taskId);
}

/**
 * Persist the current leaseStore to .formic/leases.json.
 * Fire-and-forget — callers should .catch() the returned promise.
 */
export async function persistLeases(): Promise<void> {
  try {
    const snapshot: LeaseStoreSnapshot = {
      version: '1.0',
      savedAt: new Date().toISOString(),
      leases: Array.from(leaseStore.entries()).map(([key, lease]) => ({ key, lease })),
    };
    const leasesPath = path.join(getFormicDir(), 'leases.json');
    await writeFile(leasesPath, JSON.stringify(snapshot, null, 2), 'utf-8');
  } catch (err) {
    console.warn('[LeaseManager] Failed to persist leases:', err instanceof Error ? err.message : 'Unknown error');
  }
}

/**
 * Restore non-expired leases from .formic/leases.json into leaseStore.
 * Called on server startup by the watchdog.
 */
export async function restoreLeases(): Promise<void> {
  try {
    const leasesPath = path.join(getFormicDir(), 'leases.json');
    const raw = await readFile(leasesPath, 'utf-8');
    const snapshot: LeaseStoreSnapshot = JSON.parse(raw) as LeaseStoreSnapshot;
    const now = Date.now();
    let restored = 0;
    for (const { key, lease } of snapshot.leases) {
      if (new Date(lease.expiresAt).getTime() > now) {
        leaseStore.set(key, lease);
        restored++;
      }
    }
    console.warn(`[LeaseManager] Restored ${restored} non-expired lease(s) from disk`);
  } catch (err) {
    // File not found on first startup is expected
    const message = err instanceof Error ? err.message : 'Unknown error';
    if (!message.includes('ENOENT')) {
      console.warn('[LeaseManager] Failed to restore leases:', message);
    } else {
      console.warn('[LeaseManager] No leases.json found — starting with empty lease store');
    }
  }
}

/**
 * Revert uncommitted changes on a task's exclusively-leased files after its
 * process has been stopped, so a half-written state is never handed to the
 * next lease holder (mirrors the watchdog's expired-lease path).
 */
async function revertExclusiveFiles(taskId: string, files: string[]): Promise<void> {
  if (files.length === 0) return;
  try {
    const fileList = files.map(f => `"${f}"`).join(' ');
    await execAsync(`git checkout -- ${fileList}`, { cwd: getWorkspacePath() });
    console.warn(`[LeaseManager] Reverted uncommitted changes on ${files.length} leased file(s) for task ${taskId}`);
  } catch (err) {
    console.warn(`[LeaseManager] Failed to revert leased files for task ${taskId}:`, err instanceof Error ? err.message : 'Unknown error');
  }
}

/**
 * Attempt to preempt an exclusive lease held by a lower-priority task.
 * The holder's process is stopped BEFORE its leases are released; if the
 * holder cannot be stopped, the preemption is refused — a lease must never
 * be handed to a new task while the previous holder may still be writing.
 * Returns true if the file was freed, false if preemption was not applicable
 * or was refused.
 */
export async function preemptLease(highPriorityTaskId: string, targetFilePath: string): Promise<boolean> {
  const holderLease = leaseStore.get(targetFilePath);
  if (!holderLease || holderLease.leaseType !== 'exclusive') {
    return false;
  }

  const holderId = holderLease.taskId;
  if (holderId === highPriorityTaskId) {
    return false;
  }

  const [holderTask, requesterTask] = await Promise.all([
    getTask(holderId),
    getTask(highPriorityTaskId),
  ]);

  const holderRank = PRIORITY_RANK[holderTask?.priority ?? 'medium'] ?? 1;
  const requesterRank = PRIORITY_RANK[requesterTask?.priority ?? 'medium'] ?? 1;

  if (holderRank >= requesterRank) {
    return false;
  }

  // The lease may have vanished while task lookups were awaited — distinguish
  // expiry from voluntary release rather than misattributing either.
  const leaseBeforeStop = leaseStore.get(targetFilePath);
  if (!leaseBeforeStop || leaseBeforeStop.taskId !== holderId) {
    if (new Date(holderLease.expiresAt).getTime() <= Date.now()) {
      console.warn(`[LeaseManager] Lease on ${targetFilePath} expired before preemption of task ${holderId} — no stop needed`);
    } else {
      console.warn(`[LeaseManager] Lease on ${targetFilePath} was released before preemption of task ${holderId} — no stop needed`);
    }
    return !leaseBeforeStop;
  }

  // Capture the holder's exclusive files before stopping so they can be reverted
  const holderExclusiveFiles = getLeasesByTask(holderId)
    .filter(l => l.leaseType === 'exclusive')
    .map(l => l.filePath);

  // Stop the holder's process BEFORE touching its leases
  const stopped = await requestTaskStop(holderId);
  if (!stopped) {
    console.warn(`[LeaseManager] Preemption of ${targetFilePath} refused: holder task ${holderId} could not be stopped`);
    return false;
  }

  // Holder is stopped: revert its half-written files, release, and re-queue.
  // The stop transition sets resumeFromStep for tasks past planning; the
  // 'queued' transition below preserves that marker.
  await revertExclusiveFiles(holderId, holderExclusiveFiles);
  releaseLeases(holderId);
  clearWait(holderId);
  await updateTaskStatus(holderId, 'queued', null, 'leaseManager.preemption');
  console.warn(`[LeaseManager] Preempted lease on ${targetFilePath}: stopped, reverted, and re-queued task ${holderId}`);

  return true;
}

/**
 * Detect and resolve deadlock cycles in the wait-for graph.
 * Resolves each cycle by stopping the lowest-priority task in the cycle,
 * reverting its leased files, releasing its leases, and re-queuing it.
 * If the victim cannot be stopped, resolution for that cycle is skipped this
 * tick (the watchdog re-runs detection every interval).
 * Returns the detected cycle arrays, or null if no cycles were found.
 */
export async function detectDeadlock(): Promise<string[][] | null> {
  if (waitForMap.size === 0) return null;

  // Build task-to-task wait-for graph: waiting task → holding task
  const waitGraph = new Map<string, string>();
  for (const [waitingTaskId, filePath] of waitForMap.entries()) {
    const holderLease = leaseStore.get(filePath);
    if (holderLease && holderLease.taskId !== waitingTaskId) {
      waitGraph.set(waitingTaskId, holderLease.taskId);
    }
  }

  if (waitGraph.size === 0) return null;

  // DFS-based cycle detection on a functional graph (each node has ≤1 outgoing edge)
  const cycles: string[][] = [];
  const visited = new Set<string>();

  for (const startNode of waitGraph.keys()) {
    if (visited.has(startNode)) continue;

    const path: string[] = [];
    const pathSet = new Set<string>();
    let current: string | undefined = startNode;

    while (current !== undefined && !visited.has(current)) {
      if (pathSet.has(current)) {
        const cycleStart = path.indexOf(current);
        cycles.push(path.slice(cycleStart));
        break;
      }
      path.push(current);
      pathSet.add(current);
      current = waitGraph.get(current);
    }

    for (const node of path) {
      visited.add(node);
    }
  }

  if (cycles.length === 0) return null;

  console.warn(`[LeaseManager] Detected ${cycles.length} deadlock cycle(s)`);

  // Resolve each cycle by aborting the lowest-priority task
  for (const cycle of cycles) {
    let victimId = cycle[0];
    let victimRank = PRIORITY_RANK[(await getTask(victimId))?.priority ?? 'medium'] ?? 1;

    for (const taskId of cycle.slice(1)) {
      const task = await getTask(taskId);
      const rank = PRIORITY_RANK[task?.priority ?? 'medium'] ?? 1;
      if (rank < victimRank) {
        victimId = taskId;
        victimRank = rank;
      }
    }

    // Capture the victim's exclusive files before stopping so they can be reverted
    const victimExclusiveFiles = getLeasesByTask(victimId)
      .filter(l => l.leaseType === 'exclusive')
      .map(l => l.filePath);

    // Stop the victim's process BEFORE releasing its leases; skip this cycle
    // if it cannot be stopped — never free files under a possibly-live writer
    const stopped = await requestTaskStop(victimId);
    if (!stopped) {
      console.warn(`[LeaseManager] Deadlock victim ${victimId} could not be stopped — skipping resolution this tick`);
      continue;
    }

    await revertExclusiveFiles(victimId, victimExclusiveFiles);
    releaseLeases(victimId);
    clearWait(victimId);
    await updateTaskStatus(victimId, 'queued', null, 'leaseManager.deadlock_resolution');
    console.warn(`[LeaseManager] Deadlock resolved: stopped, reverted, and re-queued task ${victimId}`);
  }

  return cycles;
}

import type { WebSocket } from 'ws';
import type { LogMessage } from '../../types/index.js';

/**
 * Board Notifier Service
 *
 * Manages WebSocket connections subscribed to board update notifications.
 * Broadcasts `board-updated` events when the board state changes (e.g., task created).
 */

// Track connections that want board update notifications
const boardConnections = new Set<WebSocket>();

// Track per-task WebSocket connections for terminal log streaming
const taskConnections = new Map<string, Set<WebSocket>>();

export function registerTaskConnection(taskId: string, ws: WebSocket): void {
  if (!taskConnections.has(taskId)) {
    taskConnections.set(taskId, new Set());
  }
  taskConnections.get(taskId)!.add(ws);
}

export function unregisterTaskConnection(taskId: string, ws: WebSocket): void {
  const connections = taskConnections.get(taskId);
  if (connections) {
    connections.delete(ws);
    if (connections.size === 0) {
      taskConnections.delete(taskId);
    }
  }
}

export function broadcastToTask(taskId: string, message: LogMessage): void {
  const connections = taskConnections.get(taskId);
  if (!connections) return;

  const data = JSON.stringify(message);
  for (const ws of connections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(data);
    }
  }
}

/**
 * Register a WebSocket connection for board update notifications
 */
export function registerBoardConnection(ws: WebSocket): void {
  boardConnections.add(ws);
  console.log('[BoardNotifier] Connection registered, total:', boardConnections.size);
}

/**
 * Unregister a WebSocket connection from board update notifications
 */
export function unregisterBoardConnection(ws: WebSocket): void {
  boardConnections.delete(ws);
  console.log('[BoardNotifier] Connection unregistered, total:', boardConnections.size);
}

/**
 * Broadcast a board-updated event to all connected clients
 * Call this after any operation that modifies the board state
 */
export function broadcastBoardUpdate(): void {
  const message = JSON.stringify({ type: 'board-updated' });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log('[BoardNotifier] Broadcast board-updated to', sentCount, 'clients');
}

/**
 * Broadcast a dependency-resolved event when a blocked task is automatically unblocked
 */
export function broadcastDependencyResolved(taskId: string, parentGoalId: string): void {
  const message = JSON.stringify({ type: 'dependency-resolved', taskId, parentGoalId });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log(`[BoardNotifier] Broadcast dependency-resolved for task ${taskId} (goal ${parentGoalId}) to ${sentCount} clients`);
}

/**
 * Broadcast a kill-switch event when the self-healing loop exhausts retries
 */
export function broadcastKillSwitch(taskId: string): void {
  const message = JSON.stringify({ type: 'kill-switch', taskId });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log(`[BoardNotifier] Broadcast kill-switch for task ${taskId} to ${sentCount} clients`);
}

/**
 * Broadcast that a task has completed (moved to review or done)
 */
export function broadcastTaskCompleted(taskId: string): void {
  const message = JSON.stringify({ type: 'task-completed', taskId });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log(`[BoardNotifier] Broadcast task-completed for task ${taskId} to ${sentCount} clients`);
}

/**
 * Broadcast that exclusive leases for a task have been released
 */
export function broadcastLeaseReleased(taskId: string, releasedFiles: string[]): void {
  const message = JSON.stringify({ type: 'lease-released', taskId, releasedFiles });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log(`[BoardNotifier] Broadcast lease-released for task ${taskId} (${releasedFiles.length} file(s)) to ${sentCount} clients`);
}

/**
 * Broadcast a workspace-changed event to all connected clients
 * Call this after switching to a different workspace
 */
export function broadcastWorkspaceChanged(workspacePath: string): void {
  const message = JSON.stringify({
    type: 'workspace-changed',
    path: workspacePath,
  });

  let sentCount = 0;
  for (const ws of boardConnections) {
    if (ws.readyState === 1) { // WebSocket.OPEN
      ws.send(message);
      sentCount++;
    }
  }

  console.log('[BoardNotifier] Broadcast workspace-changed to', sentCount, 'clients');
}

/**
 * Internal Event Emitter
 *
 * Lightweight shared EventEmitter used to decouple service-to-service
 * notifications (e.g., queue wake-up signals) without creating circular imports.
 */

import { EventEmitter } from 'node:events';

/** Event name emitted when a task transitions to 'review' or 'done' */
export const TASK_COMPLETED = 'task-completed';

/** Event name emitted when a task's file leases are released */
export const LEASE_RELEASED = 'lease-released';

/** Event name emitted when a new task is created */
export const TASK_CREATED = 'task-created';

/** Event name emitted when a task moves to queued status */
export const TASK_QUEUED = 'task-queued';

/** Event name emitted before a task execution starts */
export const BEFORE_EXECUTE = 'before-execute';

/** Event name emitted after a task execution completes (success or fail) */
export const AFTER_EXECUTE = 'after-execute';

/** Event name emitted when a task fails */
export const TASK_FAILED = 'task-failed';

/** Event name emitted when a skill file is loaded */
export const SKILL_LOADED = 'skill-loaded';

/** Event name emitted when file leases are acquired */
export const LEASE_ACQUIRED = 'lease-acquired';

/** Event name emitted on any board state change */
export const BOARD_UPDATE = 'board-update';

/** Event name emitted after server initialization completes */
export const SERVER_STARTUP = 'server-startup';

/** Event name emitted on graceful shutdown */
export const SERVER_SHUTDOWN = 'server-shutdown';

/** Event name emitted before a skill file is loaded (allows just-in-time override registration) */
export const BEFORE_SKILL_LOAD = 'before-skill-load';

/** Event name emitted when a plugin stage is registered in the pipeline */
export const STAGE_REGISTERED = 'stage-registered';

/** Event name emitted when a plugin stage is unregistered from the pipeline */
export const STAGE_UNREGISTERED = 'stage-unregistered';

/** Event name emitted when a task is updated */
export const TASK_UPDATED = 'task-updated';

/** Event name emitted when a task transitions between workflow stages */
export const TASK_STAGE_CHANGED = 'task-stage-changed';

/** Event name emitted when a plugin registers a new custom task type */
export const TASK_TYPE_REGISTERED = 'task-type-registered';

/** Shared internal event emitter instance */
export const internalEvents = new EventEmitter();

/**
 * Task stopper callback: stops the process(es) executing a task and resolves
 * true once the stop has been carried out, false if the task could not be stopped.
 */
export type TaskStopper = (taskId: string) => Promise<boolean>;

/** Injected task stopper — registered by workflow.ts at module init */
let taskStopper: TaskStopper | null = null;

/**
 * Register the task stopper callback. Used by workflow.ts to expose its
 * stop capability to lower-level services (e.g., leaseManager) without
 * creating a circular import.
 */
export function registerTaskStopper(fn: TaskStopper): void {
  taskStopper = fn;
}

/**
 * Request that a task's running process be stopped via the registered stopper.
 * Returns false when no stopper is registered or the stopper fails — callers
 * MUST treat false as "the task may still be running" and refuse any action
 * that assumes the process is dead (e.g., force-releasing its file leases).
 */
export async function requestTaskStop(taskId: string): Promise<boolean> {
  if (!taskStopper) {
    console.warn(`[InternalEvents] No task stopper registered — cannot stop task ${taskId}`);
    return false;
  }
  try {
    return await taskStopper(taskId);
  } catch (err) {
    console.error(`[InternalEvents] Task stopper failed for ${taskId}:`, err instanceof Error ? err.message : 'Unknown error');
    return false;
  }
}

/**
 * Engine Config Singleton
 * Provides synchronous access to engine settings loaded from configStore.
 * Call refreshEngineConfig() at the start of each top-level operation
 * (workflow execution, queue poll tick, watchdog scan) to pick up config changes.
 */
import { loadConfig } from './configStore.js';

export interface EngineConfig {
  maxConcurrentTasks: number;
  verifyCommand: string;
  skipVerify: boolean;
  leaseDurationMs: number;
  watchdogIntervalMs: number;
  maxYieldCount: number;
  queuePollIntervalMs: number;
  maxExecuteIterations: number;
  stepTimeoutMs: number;
  maxExecutionRetries: number;
}

export const engineConfig: EngineConfig = {
  maxConcurrentTasks: 1,
  verifyCommand: '',
  skipVerify: false,
  leaseDurationMs: 300000,
  watchdogIntervalMs: 30000,
  maxYieldCount: 50,
  queuePollIntervalMs: 5000,
  maxExecuteIterations: 5,
  stepTimeoutMs: 6000000,
  maxExecutionRetries: 3,
};

export async function refreshEngineConfig(): Promise<void> {
  const config = await loadConfig();
  const s = config.settings;
  engineConfig.maxConcurrentTasks = s.maxConcurrentSessions ?? 1;
  engineConfig.verifyCommand = s.verifyCommand ?? '';
  engineConfig.skipVerify = s.skipVerify ?? false;
  engineConfig.leaseDurationMs = s.leaseDurationMs ?? 300000;
  engineConfig.watchdogIntervalMs = s.watchdogIntervalMs ?? 30000;
  engineConfig.maxYieldCount = s.maxYieldCount ?? 50;
  engineConfig.queuePollIntervalMs = s.queuePollIntervalMs ?? 5000;
  engineConfig.maxExecuteIterations = s.maxExecuteIterations ?? 5;
  engineConfig.stepTimeoutMs = s.stepTimeoutMs ?? 6000000;
  engineConfig.maxExecutionRetries = s.maxExecutionRetries ?? 3;
}

